document.addEventListener('DOMContentLoaded',function(){
  // Toast notification system
  window.showToast=function(message,type,duration){
    type=type||'info';
    duration=duration||3000;
    var container=document.getElementById('toast-container');
    if(!container){
      container=document.createElement('div');
      container.id='toast-container';
      container.className='toast-container';
      container.setAttribute('aria-live','polite');
      container.setAttribute('role','status');
      document.body.appendChild(container);
    }
    var toast=document.createElement('div');
    toast.className='toast toast-'+type;
    toast.setAttribute('role','alert');
    var icon='';
    if(type==='success')icon='&#10003; ';
    else if(type==='error')icon='&#10007; ';
    else if(type==='warning')icon='&#9888; ';
    else icon='&#8505; ';
    toast.innerHTML='<span>'+icon+message+'</span>';
    container.appendChild(toast);
    setTimeout(function(){
      toast.classList.add('toast-exit');
      setTimeout(function(){toast.remove()},300);
    },duration);
  };

  // Loading spinner helper
  window.setLoading=function(buttonId,isLoading){
    var btn=document.getElementById(buttonId);
    if(!btn)return;
    if(isLoading){
      btn.disabled=true;
      btn.dataset.originalText=btn.textContent;
      btn.innerHTML='<span class="spinner"></span> <span>'+btn.dataset.originalText+'</span>';
    }else{
      btn.disabled=false;
      btn.textContent=btn.dataset.originalText||'提交';
    }
  };

  // Mobile menu toggle with overlay
  var navToggler=document.querySelector('.navbar-toggler');
  var navLinks=document.querySelector('.nav-links');
  var navOverlay=document.getElementById('navOverlay');
  
  function closeMobileMenu(){
    if(navLinks)navLinks.classList.remove('show');
    if(navOverlay){navOverlay.classList.remove('show');navOverlay.setAttribute('aria-hidden','true')}
    if(navToggler)navToggler.setAttribute('aria-expanded','false');
    document.body.style.overflow='';
  }
  
  function openMobileMenu(){
    if(navLinks)navLinks.classList.add('show');
    if(navOverlay){navOverlay.classList.add('show');navOverlay.setAttribute('aria-hidden','false')}
    if(navToggler)navToggler.setAttribute('aria-expanded','true');
    document.body.style.overflow='hidden';
  }
  
  if(navToggler&&navLinks){
    navToggler.addEventListener('click',function(){
      var expanded=navToggler.getAttribute('aria-expanded')==='true';
      if(expanded)closeMobileMenu();
      else openMobileMenu();
    });
    
    if(navOverlay){
      navOverlay.addEventListener('click',closeMobileMenu);
    }
    
    // Close menu when clicking nav links
    navLinks.querySelectorAll('a').forEach(function(link){
      link.addEventListener('click',closeMobileMenu);
    });
    
    // Close on Escape key
    document.addEventListener('keydown',function(e){
      if(e.key==='Escape'&&navLinks.classList.contains('show')){
        closeMobileMenu();
        navToggler.focus();
      }
    });
  }

  // Smooth scroll for anchor links
  document.querySelectorAll('a[href^="#"]').forEach(function(anchor){
    anchor.addEventListener('click',function(e){
      var target=document.querySelector(this.getAttribute('href'));
      if(target){
        e.preventDefault();
        target.scrollIntoView({behavior:'smooth',block:'start'});
      }
    });
  });

  // Animate elements on scroll
  var observer=new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(entry.isIntersecting){
        entry.target.classList.add('animate-fadeIn');
        observer.unobserve(entry.target);
      }
    });
  },{threshold:0.1});

  document.querySelectorAll('.card,.stat-card').forEach(function(el){
    el.style.opacity='0';
    observer.observe(el);
  });

  // Progress bar animation
  var progressBars=document.querySelectorAll('.progress-bar');
  progressBars.forEach(function(bar){
    var width=bar.style.width;
    bar.style.width='0';
    setTimeout(function(){bar.style.width=width},300);
  });

  // Active nav link highlight
  var currentPath=window.location.pathname;
  document.querySelectorAll('.nav-links a').forEach(function(link){
    if(link.getAttribute('href')===currentPath){
      link.classList.add('active');
    }
  });

  // Form validation enhancement
  var forms=document.querySelectorAll('form');
  forms.forEach(function(form){
    var inputs=form.querySelectorAll('input,textarea,select');
    inputs.forEach(function(input){
      input.addEventListener('blur',function(){
        validateField(input);
      });
      input.addEventListener('input',function(){
        if(input.classList.contains('is-invalid')){
          validateField(input);
        }
      });
    });

    form.addEventListener('submit',function(e){
      var isValid=true;
      inputs.forEach(function(input){
        if(!validateField(input)){
          isValid=false;
        }
      });
      if(!isValid){
        e.preventDefault();
        showToast('请修正表单中的错误','error');
      }
    });
  });

  function validateField(input){
    if(!input.required)return true;
    var errorId=input.id+'-error';
    var errorMsg=document.getElementById(errorId);
    
    if(!input.value.trim()){
      showFieldError(input,errorId,'此字段为必填项');
      return false;
    }
    
    if(input.minLength&&input.value.length<input.minLength){
      showFieldError(input,errorId,'至少需要'+input.minLength+'个字符');
      return false;
    }
    
    if(input.type==='email'&&input.value){
      var emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if(!emailRegex.test(input.value)){
        showFieldError(input,errorId,'请输入有效的邮箱地址');
        return false;
      }
    }
    
    if(input.id==='confirm_password'){
      var password=document.getElementById('password');
      if(password&&input.value!==password.value){
        showFieldError(input,errorId,'两次输入的密码不一致');
        return false;
      }
    }
    
    clearFieldError(input,errorId);
    return true;
  }

  function showFieldError(input,errorId,message){
    input.classList.add('is-invalid');
    input.classList.remove('is-valid');
    input.setAttribute('aria-invalid','true');
    
    var errorMsg=document.getElementById(errorId);
    if(!errorMsg){
      errorMsg=document.createElement('div');
      errorMsg.id=errorId;
      errorMsg.className='field-error';
      errorMsg.setAttribute('role','alert');
      input.parentNode.appendChild(errorMsg);
    }
    errorMsg.textContent=message;
    return errorMsg;
  }

  function clearFieldError(input,errorId){
    input.classList.remove('is-invalid');
    input.classList.add('is-valid');
    input.removeAttribute('aria-invalid');
    
    var errorMsg=document.getElementById(errorId);
    if(errorMsg){
      errorMsg.textContent='';
    }
  }

  // Keyboard navigation enhancement for dropdowns
  var dropdowns=document.querySelectorAll('.dropdown');
  dropdowns.forEach(function(dropdown){
    var trigger=dropdown.querySelector('.dropdown-trigger');
    var menu=dropdown.querySelector('.dropdown-menu');
    
    if(trigger&&menu){
      trigger.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){
          e.preventDefault();
          var expanded=trigger.getAttribute('aria-expanded')==='true';
          trigger.setAttribute('aria-expanded',!expanded);
          menu.style.display=expanded?'none':'block';
        }
        if(e.key==='Escape'){
          trigger.setAttribute('aria-expanded','false');
          menu.style.display='none';
          trigger.focus();
        }
      });

      var links=menu.querySelectorAll('a');
      links.forEach(function(link,index){
        link.addEventListener('keydown',function(e){
          if(e.key==='ArrowDown'){
            e.preventDefault();
            var next=links[(index+1)%links.length];
            next.focus();
          }
          if(e.key==='ArrowUp'){
            e.preventDefault();
            var prev=links[(index-1+links.length)%links.length];
            prev.focus();
          }
          if(e.key==='Escape'){
            menu.style.display='none';
            trigger.focus();
          }
        });
      });
    }
  });

  // Skip link focus management
  var skipLink=document.querySelector('.skip-link');
  if(skipLink){
    skipLink.addEventListener('click',function(e){
      var targetId=this.getAttribute('href').substring(1);
      var target=document.getElementById(targetId);
      if(target){
        target.setAttribute('tabindex','-1');
        target.focus();
      }
    });
  }
});
